"use strict";(globalThis.webpackChunknoordung_wiki=globalThis.webpackChunknoordung_wiki||[]).push([[567],{5226(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/","label":"NSLP Stack","docId":"index","unlisted":false},{"type":"category","label":"L1 - Link layer","collapsible":false,"collapsed":false,"items":[{"type":"link","href":"/l1/nslp-uart","label":"NSLP/UART","docId":"l1/nslp-uart","unlisted":false},{"type":"link","href":"/l1/nslp-can-fd","label":"NSLP/CAN-FD","docId":"l1/nslp-can-fd","unlisted":false}],"href":"/l1/"},{"type":"link","href":"/l2/","label":"L2 - Network layer","docId":"l2/index","unlisted":false},{"type":"category","label":"L3 - Transport layer","collapsible":false,"collapsed":false,"items":[{"type":"link","href":"/l3/sl-tcp","label":"SL-TCP","docId":"l3/sl-tcp","unlisted":false},{"type":"link","href":"/l3/sl-udp","label":"SL-UDP","docId":"l3/sl-udp","unlisted":false}],"href":"/l3/"},{"type":"category","label":"L4 - Application layer","collapsible":false,"collapsed":false,"items":[{"type":"link","href":"/l4/sl-sp","label":"SL-SP","docId":"l4/sl-sp","unlisted":false}],"href":"/l4/"}]},"docs":{"index":{"id":"index","title":"Noordung ServiceLink Protocols Stack","description":"This protocol specification is currently a Work in Progress. The architectural concepts, frame structures, and bit-level arrangements detailed on this page are under heavy development and are highly subject to breaking changes without notice.","sidebar":"tutorialSidebar"},"l1/index":{"id":"l1/index","title":"L1 - Link layer","description":"The Layer 1 (Link Layer) serves as the foundational bridge between the logical routing of the NSLP stack and the physical realities of your hardware. While the upper layers deal in pristine data structures and standardized addressing, Layer 1 is responsible for interacting with the actual transmission medium.","sidebar":"tutorialSidebar"},"l1/nslp-can-fd":{"id":"l1/nslp-can-fd","title":"NSLP/CAN-FD","description":"Work in progress","sidebar":"tutorialSidebar"},"l1/nslp-uart":{"id":"l1/nslp-uart","title":"NSLP/UART","description":"NSLP/UART is the officially supported Layer 1 protocol for serial communication. It is designed to bridge the gap between structured Layer 2 network packets and the raw, continuous byte streams typical of UART (Universal Asynchronous Receiver-Transmitter) connections.","sidebar":"tutorialSidebar"},"l2/index":{"id":"l2/index","title":"L2 - Network layer","description":"The Layer 2 (Network Layer) acts as the great equalizer for the NSLP stack, responsible for taking potentially large Transport Layer (L3) payloads and segmenting them into strict, predictable Network MTUs (Maximum Transmission Units). Because the overall NSLP packet size is strictly capped at 255 bytes to accommodate highly constrained mediums (e.g., LoRa, CAN), L2 ensures that no single data payload exceeds the 250-byte limit. When an L3 payload surpasses this boundary, L2 automatically slices the data into sequential chunks, isolating the upper transport protocols from these rigid, network-level size constraints.","sidebar":"tutorialSidebar"},"l3/index":{"id":"l3/index","title":"L3 - Transport layer","description":"The Layer 3 (Transport Layer) elevates the stack\'s focus from simply moving bytes between devices to managing application-level connections and delivery policies. While Layer 2 ensures that data reaches the correct physical machine within strict MTU limits, Layer 3 is responsible for port-level routing, ensuring the payload reaches the exact process or code block meant to handle it. It is at this layer that developers choose the reliability paradigm that best fits their data: guaranteed, ordered delivery for critical state changes, or lightweight, unacknowledged streams for high-frequency sensor telemetry.","sidebar":"tutorialSidebar"},"l3/sl-tcp":{"id":"l3/sl-tcp","title":"SL-TCP","description":"ServiceLink Transmission Control Protocol (SL-TCP) is the connection-oriented, stateful transport protocol of the NSLP stack. It is designed specifically for mission-critical payloads where guaranteed, strictly ordered delivery is strictly required (such as dispatching system configuration changes, triggering physical actuators, or sending state-machine commands).","sidebar":"tutorialSidebar"},"l3/sl-udp":{"id":"l3/sl-udp","title":"SL-UDP","description":"ServiceLink User Datagram Protocol (SL-UDP) is the lightweight, stateless transport protocol of the NSLP stack. It strips away the complex state machines, blocking loops, and delivery guarantees of SL-TCP to provide a fast, \\"fire-and-forget\\" communication channel.","sidebar":"tutorialSidebar"},"l4/index":{"id":"l4/index","title":"L4 - Application layer","description":"The Layer 4 (Application Layer) is the culmination of the entire NSLP stack. While Layers 1 through 3 are exclusively focused on how bytes are transported across the network, Layer 4 focuses entirely on what those bytes actually mean.","sidebar":"tutorialSidebar"},"l4/sl-sp":{"id":"l4/sl-sp","title":"SL-SP","description":"Work in progress","sidebar":"tutorialSidebar"}}}}')}}]);